{
  "rules": {
    "teams": {
      "$teamId": {
        "users": {
          ".read": "auth != null",
          ".write": "auth != null",
          "$login": {
            ".validate": "newData.hasChildren(['uid', 'login', 'role']) && newData.child('role').val().matches(/^(admin|employee)$/) && newData.child('login').isString() && newData.child('uid').isString()"
          }
        },
        "tasks": {
          "$taskId": {
            ".read": "auth != null",
            ".write": "auth != null",
            ".validate": "newData.hasChildren(['id', 'title', 'status', 'createdBy']) && newData.child('status').val().matches(/^(urgent|in_progress|done)$/) && newData.child('title').isString() && newData.child('createdBy').isString() && newData.child('id').isString()"
          }
        }
      }
    }
  }
}
